"""Axis test policy runtime node.

Subclass of PolicyRuntimeBase that uses the axis_test backend.
No camera or instruction subscriptions — only joint_states for IK."""

from sensor_msgs.msg import JointState

from franka_policy_runtime.base_node import PolicyRuntimeBase, run_node
from franka_policy_runtime.observers.axis_test import AxisTestObserver


class AxisTestRuntime(PolicyRuntimeBase):
    """Policy runtime for single-axis micro-motion testing."""

    def __init__(self) -> None:
        super().__init__(node_name="axis_test_runtime")

    # ------------------------------------------------------------------
    # Extension points
    # ------------------------------------------------------------------

    def _declare_parameters(self) -> None:
        """No additional parameters — dimension/max_steps live on server side."""

    def _create_observer(self):
        return AxisTestObserver(self._joint_names)

    def _create_subscriptions(self) -> None:
        """Only subscribe to joint_states (needed for IK seed).

        Intentionally do NOT subscribe to image, depth, camera_info,
        or instruction topics — axis test needs none of these.
        """
        self.create_subscription(
            JointState,
            str(self.get_parameter("joint_state_topic").value),
            self._joint_state_cb,
            10,
        )


def main(args=None) -> None:
    run_node(AxisTestRuntime, args=args)
